1	import { readFileSync } from "fs";
2	import { quote, claim } from "./claim-office.js";
3	
4	const input = JSON.parse(readFileSync(0 as unknown as string, "utf-8"));
5	const customer = { yearsAsCustomer: input.customer.yearsWithMHPCO };
6	const results: unknown[] = [];
7	let contractNumber = 1;
8	const policiesByStep: Record<number, unknown[]> = {};
9	const policyPayouts: Record<number, number> = {};
10	
11	for (let i = 0; i < input.steps.length; i++) {
12	  const step = input.steps[i];
13	  if (step.op === "quote") {
14	    const premium = quote(step.items, customer, contractNumber);
15	    policiesByStep[i] = step.items;
16	    policyPayouts[i] = 0;
17	    results.push({ premium });
18	    contractNumber++;
19	  } else if (step.op === "claim") {
20	    const policyIndex = step.policy;
21	    const policyItems = policiesByStep[policyIndex];
22	    const previousPayouts = policyPayouts[policyIndex];
23	    const result = claim(policyItems, step.incident.damages, previousPayouts);
24	    policyPayouts[policyIndex] = previousPayouts + result.payout;
25	    results.push({ payout: result.payout, remainingCap: result.remainingCap });
26	  }
27	}
28	
29	process.stdout.write(JSON.stringify({ results }));
