1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 1 / 10;
3	const LOYALTY_DISCOUNT_RATE = 2 / 10;
4	const LOYALTY_YEARS_THRESHOLD = 2;
5	const FOLLOW_UP_DISCOUNT_RATE = 15 / 100;
6	
7	const BASE_PREMIUMS: Record<string, number> = {
8	  sword: 100,
9	  amulet: 60,
10	  staff: 80,
11	  potion: 40,
12	  rune: 25,
13	  moonstone: 25,
14	};
15	
16	const CURSED_SURCHARGE_RATE = 1 / 2;
17	
18	const COMPONENT_TYPES = ["rune", "moonstone"];
19	const BLOCK_SIZE = 3;
20	const BLOCK_PREMIUM = 60;
21	
22	const HIGHLY_ENCHANTED_THRESHOLD = 5;
23	const ENCHANTMENT_SURCHARGE_RATE = 3 / 10;
24	
25	type Item = { type: string; enchantment?: number; cursed?: boolean };
26	type Customer = { yearsAsCustomer: number };
27	
28	const isComponent = (item: Item): boolean =>
29	  COMPONENT_TYPES.includes(item.type);
30	
31	const hasEnchantmentAtLeast = (item: Item, threshold: number): boolean =>
32	  (item.enchantment ?? 0) >= threshold;
33	
34	const isHighlyEnchanted = (item: Item): boolean =>
35	  hasEnchantmentAtLeast(item, HIGHLY_ENCHANTED_THRESHOLD);
36	
37	const calculateItemBasePremium = (item: Item): number =>
38	  BASE_PREMIUMS[item.type] ?? 0;
39	
40	const calculateItemSurcharges = (item: Item, basePremium: number): number => {
41	  const cursedSurcharge = item.cursed ? basePremium * CURSED_SURCHARGE_RATE : 0;
42	  const enchantmentSurcharge = isHighlyEnchanted(item)
43	    ? basePremium * ENCHANTMENT_SURCHARGE_RATE
44	    : 0;
45	  return cursedSurcharge + enchantmentSurcharge;
46	};
47	
48	const countComponentsByType = (items: Item[]): Record<string, number> => {
49	  const counts: Record<string, number> = {};
50	  for (const item of items) {
51	    if (isComponent(item)) {
52	      counts[item.type] = (counts[item.type] ?? 0) + 1;
53	    }
54	  }
55	  return counts;
56	};
57	
58	const hasBlock = (componentCounts: Record<string, number>, type: string): boolean =>
59	  componentCounts[type] === BLOCK_SIZE;
60	
61	export const quote = (items: Item[], customer: Customer, contractNumber: number): number => {
62	  const componentCounts = countComponentsByType(items);
63	
64	  let policyBasePremium = 0;
65	  let itemSurcharges = 0;
66	
67	  for (const item of items) {
68	    if (isComponent(item) && hasBlock(componentCounts, item.type)) {
69	      continue;
70	    }
71	    const basePremium = calculateItemBasePremium(item);
72	    policyBasePremium += basePremium;
73	    itemSurcharges += calculateItemSurcharges(item, basePremium);
74	  }
75	
76	  for (const type of COMPONENT_TYPES) {
77	    if (hasBlock(componentCounts, type)) {
78	      policyBasePremium += BLOCK_PREMIUM;
79	    }
80	  }
81	
82	  const firstInsuranceSurcharge = policyBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
83	  const loyaltyDiscount =
84	    customer.yearsAsCustomer >= LOYALTY_YEARS_THRESHOLD
85	      ? policyBasePremium * LOYALTY_DISCOUNT_RATE
86	      : 0;
87	  const followUpDiscount =
88	    contractNumber > 1 ? policyBasePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
89	
90	  const totalPremium =
91	    policyBasePremium + firstInsuranceSurcharge - loyaltyDiscount - followUpDiscount + itemSurcharges;
92	
93	  return Math.ceil(totalPremium) + PROCESSING_FEE;
94	};
95	
96	type Damage = { itemType: string; amount: number };
97	type ClaimResult = { payout: number; remainingCap: number };
98	
99	const INSURANCE_VALUES: Record<string, number> = {
100	  sword: 1000,
101	  amulet: 600,
102	  staff: 800,
103	  potion: 400,
104	  rune: 250,
105	  moonstone: 250,
106	};
107	
108	const DEDUCTIBLE = 100;
109	const CAP_MULTIPLIER = 2;
110	const CLAIM_HIGH_ENCHANTMENT_THRESHOLD = 8;
111	const CLAIM_HIGH_ENCHANTMENT_RATE = 1 / 2;
112	
113	const isHighlyEnchantedClaim = (item: Item): boolean =>
114	  hasEnchantmentAtLeast(item, CLAIM_HIGH_ENCHANTMENT_THRESHOLD);
115	
116	const findPolicyItem = (policyItems: Item[], itemType: string): Item | undefined =>
117	  policyItems.find((item) => item.type === itemType);
118	
119	const calculateEffectiveDamage = (damage: Damage, policyItems: Item[]): number => {
120	  const matchedItem = findPolicyItem(policyItems, damage.itemType);
121	  if (matchedItem && isHighlyEnchantedClaim(matchedItem)) {
122	    return damage.amount * CLAIM_HIGH_ENCHANTMENT_RATE;
123	  }
124	  return damage.amount;
125	};
126	
127	export const claim = (
128	  policyItems: Item[],
129	  damages: Damage[],
130	  previousPayouts: number,
131	): ClaimResult => {
132	  const insuranceSum = policyItems.reduce(
133	    (sum, item) => sum + (INSURANCE_VALUES[item.type] ?? 0),
134	    0,
135	  );
136	  const cap = CAP_MULTIPLIER * insuranceSum;
137	  const availableCap = cap - previousPayouts;
138	
139	  const rawPayout = damages.reduce((sum, damage) => {
140	    const effectiveAmount = calculateEffectiveDamage(damage, policyItems);
141	    return sum + Math.max(0, effectiveAmount - DEDUCTIBLE);
142	  }, 0);
143	
144	  const cappedPayout = Math.min(rawPayout, availableCap);
145	  const roundedPayout = Math.floor(cappedPayout);
146	  return { payout: roundedPayout, remainingCap: availableCap - roundedPayout };
147	};
